code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});

let i = 0;
let t;
let input = [];
readline.on('line', line => {
    if (i === 0) {
        t = parseInt(line);
    } else {
        input.push(line.split(' ').map(num => parseInt(num)));
    }
    i++;
    if (i > t) {
        readline.close();
        main();
    }
});

function countBits(n) {
    let count = 0;
    while (n) {
        count += n & 1;
        n >>= 1;
    }
    return count;
}

function main() {
    for (let i = 0; i < t; i++) {
        let [a, b] = input[i];
        console.log(countBits(a) + countBits(b));
    }
}

